let rows;
if (Array.isArray(items[0]?.json)) {
  rows = items[0].json;
} else {
  rows = items.map(i => i.json);
}
// Filter out empty objects and items without id
rows = rows.filter(r => r && r.id);
if (!rows || rows.length === 0) return [];
return rows.map(c => ({ json: c }));

const cluster = $('Normalize Input').item.json;
let sources = items.map(i => i.json).filter(s => s && s.title);

if (sources.length === 0) {
  sources = [{ title: cluster.topic || 'Tecnologia', summary: 'Noticia sobre ' + (cluster.topic || 'tecnologia'), source_name: 'Vision7', canonical_url: '', topic: cluster.topic }];
}

const sourceTexts = sources.map((s, i) => {
  return 'Fonte ' + (i + 1) + ' (' + (s.source_name || 'desconhecido') + '):\nTitulo: ' + (s.title || '') + '\nResumo: ' + (s.summary || s.content || '') + '\nURL: ' + (s.canonical_url || '');
}).join('\n\n');

const topicMap = {
  'ia': 'Inteligencia Artificial',
  'ciberseguranca': 'Ciberseguranca',
  'automacao': 'Automacao',
  'geral': 'Tecnologia'
};

const topicLabel = topicMap[cluster.topic] || cluster.topic || 'Tecnologia';

const prompt = 'Es um jornalista tecnologico portugues do portal Vision7. Escreve um artigo ORIGINAL baseado nas fontes abaixo.\n\nREGRAS:\n- Artigo 100% original, NAO copies frases das fontes\n- Tom informativo e profissional, portugues europeu\n- Entre 300 e 600 palavras\n- Inclui titulo atrativo (sem clickbait)\n- Inclui subtitulo de 1 linha\n- Inclui excerpt (resumo de 2 frases)\n- Corpo em Markdown\n- Tema: ' + topicLabel + '\n- NAO inventes dados ou estatisticas\n- Cita fontes quando relevante\n\nFONTES:\n' + sourceTexts + '\n\nResponde APENAS em JSON valido:\n{\n  "title": "...",\n  "subtitle": "...",\n  "excerpt": "...",\n  "body_markdown": "...",\n  "topic": "' + cluster.topic + '"\n}';

return [{
  json: {
    cluster_id: cluster.id,
    fingerprint: cluster.fingerprint,
    confidence_score: cluster.confidence_score,
    source_count: sources.length,
    topic: cluster.topic,
    prompt: prompt
  }
}];

const prev = $('Build AI Prompt').item.json;

const body = {
  model: 'llama-3.1-8b-instant',
  temperature: 0.7,
  max_tokens: 2000,
  messages: [
    { role: 'system', content: 'Es um jornalista tech portugues. Responde SEMPRE em JSON valido.' },
    { role: 'user', content: prev.prompt }
  ]
};

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'Authorization': 'Bearer SUA_GROQ_API_KEY',
      'Content-Type': 'application/json'
    },
    body: body,
    json: true
  });
  return [{ json: response }];
} catch (e) {
  return [{ json: { error: { message: e.message }, choices: [] } }];
}

const prev = $('Build AI Prompt').item.json;
const response = $json;

function extractField(text, field) {
  const re = new RegExp('"' + field + '"\\s*:\\s*"');
  const m = re.exec(text);
  if (!m) return '';
  let start = m.index + m[0].length;
  let result = '';
  for (let i = start; i < text.length; i++) {
    if (text[i] === '\\') { result += text[i] + (text[i+1]||''); i++; continue; }
    if (text[i] === '"') {
      const after = text.substring(i+1).trimStart();
      if (after[0] === ',' || after[0] === '}') break;
      result += text[i];
      continue;
    }
    result += text[i];
  }
  return result.replace(/\n/g, ' ').replace(/\r/g, '').replace(/\t/g, ' ');
}

let article;
try {
  let content = response.choices[0].message.content;
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Strategy 1: Direct parse
  try {
    article = JSON.parse(content);
  } catch (e1) {
    // Strategy 2: Fix control chars
    try {
      let fixed = '';
      let inStr = false;
      let esc = false;
      for (let i = 0; i < content.length; i++) {
        const ch = content[i];
        if (esc) { fixed += ch; esc = false; continue; }
        if (ch === '\\') { fixed += ch; esc = true; continue; }
        if (ch === '"') { inStr = !inStr; fixed += ch; continue; }
        if (inStr && ch === '\n') { fixed += '\\n'; continue; }
        if (inStr && ch === '\r') { fixed += '\\r'; continue; }
        if (inStr && ch === '\t') { fixed += '\\t'; continue; }
        fixed += ch;
      }
      article = JSON.parse(fixed);
    } catch (e2) {
      // Strategy 3: Regex extraction field by field
      article = {
        title: extractField(content, 'title'),
        subtitle: extractField(content, 'subtitle'),
        excerpt: extractField(content, 'excerpt'),
        body_markdown: extractField(content, 'body_markdown'),
        topic: extractField(content, 'topic') || prev.topic
      };
      if (!article.title || article.title.length < 5) throw new Error('All parse strategies failed');
    }
  }
} catch (e) {
  return [{ json: { error: 'Failed to parse AI response: ' + e.message, cluster_id: prev.cluster_id, skip: true } }];
}

const audit = {
  has_title: Boolean(article.title && article.title.length > 10),
  has_body: Boolean(article.body_markdown && article.body_markdown.length > 200),
  has_excerpt: Boolean(article.excerpt && article.excerpt.length > 20),
  body_length: (article.body_markdown || '').length,
  no_suspicious_urls: !/https?:\/\/(?!vision7|google|microsoft|apple|meta)/i.test(article.body_markdown || ''),
  language_ok: /[a-zA-Z]/.test(article.body_markdown || '')
};

const passedChecks = Object.values(audit).filter(v => v === true).length;
const totalChecks = Object.keys(audit).length - 1;
const editorial_score = Math.round((passedChecks / totalChecks) * 100);

const slug = (article.title || 'sem-titulo')
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 80)
  + '-' + Date.now().toString(36);

return [{
  json: {
    cluster_id: prev.cluster_id,
    fingerprint: prev.fingerprint,
    title: article.title || 'Sem titulo',
    subtitle: article.subtitle || null,
    slug: slug,
    excerpt: article.excerpt || null,
    body_markdown: article.body_markdown || '',
    body_html: null,
    language: 'pt',
    editorial_score: editorial_score,
    confidence_score: prev.confidence_score,
    status: editorial_score >= 70 ? 'ready' : 'draft',
    tone_profile: 'vision7',
    topic: prev.topic,
    model_info: {
      model: 'llama-3.1-8b-instant',
      source_count: prev.source_count,
      generated_at: new Date().toISOString()
    },
    moderation: audit,
    skip: false
  }
}];

const post = $json;
const SUPABASE_URL = 'https://stpusdeqwbckvfsitsld.supabase.co';
const SUPABASE_KEY = 'SUA_SERVICE_ROLE_KEY';
const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// 1. Save curated post
let saved = null;
try {
  saved = await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/curated_posts',
    headers: headers,
    body: {
      cluster_id: post.cluster_id,
      title: post.title,
      subtitle: post.subtitle,
      slug: post.slug,
      excerpt: post.excerpt,
      body_markdown: post.body_markdown,
      body_html: post.body_html,
      language: post.language,
      editorial_score: post.editorial_score,
      confidence_score: post.confidence_score,
      status: post.status,
      tone_profile: post.tone_profile,
      model_info: post.model_info,
      moderation: post.moderation
    },
    json: true
  });
} catch (e) {
  return [{ json: { error: 'Save curated failed: ' + e.message, cluster_id: post.cluster_id } }];
}

// 2. Auto-promote to posts table as draft (for admin review)
let draftSlug = (post.slug || post.title.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''))
  + '-' + Date.now().toString(36);

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/posts',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      title: post.title,
      slug: draftSlug,
      excerpt: post.excerpt || post.subtitle || '',
      content: post.body_html || post.body_markdown,
      status: 'draft',
      featured: false,
      tags: ['automação', 'ia'],
      read_time: Math.max(1, Math.ceil((post.body_markdown || '').length / 1200)) + ' min',
      author_name: 'Vision7 IA'
    },
    json: true
  });

  // Mark curated as published since it's now in editorial
  if (saved && Array.isArray(saved) && saved[0]?.id) {
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: SUPABASE_URL + '/rest/v1/curated_posts?id=eq.' + saved[0].id,
        headers: {
          'apikey': SUPABASE_KEY,
          'Authorization': 'Bearer ' + SUPABASE_KEY,
          'Content-Type': 'application/json',
        },
        body: { status: 'published' },
        json: true
      });
    } catch (e) { /* non-fatal */ }
  }
} catch (e) {
  // Non-fatal — curated post is still saved, manual promote possible
  return [{ json: { success: true, draft_auto: false, error_draft: e.message, title: post.title } }];
}

// 3. Cleanup staging
try {
  await this.helpers.httpRequest({
    method: 'DELETE',
    url: SUPABASE_URL + '/rest/v1/news_staging?duplicate_fingerprint=eq.' + post.fingerprint + '&processed=eq.true',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY },
    json: true
  });
} catch (e) { /* non-fatal */ }

// 4. Cleanup cluster
try {
  await this.helpers.httpRequest({
    method: 'DELETE',
    url: SUPABASE_URL + '/rest/v1/news_clusters?id=eq.' + post.cluster_id,
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY },
    json: true
  });
} catch (e) { /* non-fatal */ }

return [{ json: { success: true, draft_auto: true, title: post.title, slug: draftSlug, editorial_score: post.editorial_score, status: 'draft' } }];
